import 'package:flutter/material.dart';import '../models/budget.dart';import '../models/category.dart';import '../models/recurring_payment.dart';import '../models/transaction.dart';import 'package:intl/intl.dart';class MockDataService {  static final List<Category> _categories = [    const Category(id: '1', name: 'Groceries', icon: Icons.local_grocery_store, color: Colors.green),    const Category(id: '2', name: 'Dining', icon: Icons.restaurant, color: Colors.orange),    const Category(id: '3', name: 'Transport', icon: Icons.directions_car, color: Colors.blue),    const Category(id: '4', name: 'Entertainment', icon: Icons.movie, color: Colors.purple),    const Category(id: '5', name: 'Utilities', icon: Icons.lightbulb, color: Colors.red),    const Category(id: '6', name: 'Shopping', icon: Icons.shopping_bag, color: Colors.pink),    const Category(id: '7', name: 'Salary', icon: Icons.attach_money, color: Colors.teal),    const Category(id: '8', name: 'Health', icon: Icons.health_and_safety, color: Colors.cyan),  ];  static List<Category> get categories => _categories;  static Category getCategoryById(String id) =>      _categories.firstWhere((cat) => cat.id == id,          orElse: () => _categories.first); // Default to first category  static final List<Transaction> _transactions = [    Transaction(      id: 't1',      merchant: 'Whole Foods',      date: DateTime.now().subtract(const Duration(days: 1)),      amount: -75.50,      category: _categories[0],    ),    Transaction(      id: 't2',      merchant: 'Starbucks',      date: DateTime.now().subtract(const Duration(days: 2)),      amount: -5.20,      category: _categories[1],    ),    Transaction(      id: 't3',      merchant: 'Uber',      date: DateTime.now().subtract(const Duration(days: 3)),      amount: -18.00,      category: _categories[2],    ),    Transaction(      id: 't4',      merchant: 'Netflix',      date: DateTime.now().subtract(const Duration(days: 5)),      amount: -15.99,      category: _categories[3],    ),    Transaction(      id: 't5',      merchant: 'Electricity Bill',      date: DateTime.now().subtract(const Duration(days: 7)),      amount: -120.00,      category: _categories[4],    ),    Transaction(      id: 't6',      merchant: 'Zara',      date: DateTime.now().subtract(const Duration(days: 10)),      amount: -89.99,      category: _categories[5],    ),    Transaction(      id: 't7',      merchant: 'Salary Deposit',      date: DateTime.now().subtract(const Duration(days: 15)),      amount: 2500.00,      category: _categories[6],    ),    Transaction(      id: 't8',      merchant: 'Pharmacy',      date: DateTime.now().subtract(const Duration(days: 18)),      amount: -30.50,      category: _categories[7],    ),    Transaction(      id: 't9',      merchant: 'Local Cafe',      date: DateTime.now().subtract(const Duration(days: 20)),      amount: -8.75,      category: _categories[1],    ),    Transaction(      id: 't10',      merchant: 'Amazon',      date: DateTime.now().subtract(const Duration(days: 22)),      amount: -45.00,      category: _categories[5],    ),    Transaction(      id: 't11',      merchant: 'Shell Gas',      date: DateTime.now().subtract(const Duration(days: 25)),      amount: -60.00,      category: _categories[2],    ),    Transaction(      id: 't12',      merchant: 'Cinema',      date: DateTime.now().subtract(const Duration(days: 28)),      amount: -25.00,      category: _categories[3],    ),  ];  static List<Transaction> get transactions => _transactions;  static final List<Budget> _budgets = [    Budget(      id: 'b1',      name: 'Monthly Dining',      totalAmount: 500.00,      spentAmount: 350.00,      categories: [_categories[1]],      frequency: BudgetFrequency.monthly,      startDate: DateTime.now().subtract(const Duration(days: 20)),    ),    Budget(      id: 'b2',      name: 'Groceries',      totalAmount: 300.00,      spentAmount: 280.00,      categories: [_categories[0]],      frequency: BudgetFrequency.monthly,      startDate: DateTime.now().subtract(const Duration(days: 20)),      alertThreshold: 0.9,    ),    Budget(      id: 'b3',      name: 'Entertainment',      totalAmount: 200.00,      spentAmount: 100.00,      categories: [_categories[3]],      frequency: BudgetFrequency.monthly,      startDate: DateTime.now().subtract(const Duration(days: 20)),    ),  ];  static List<Budget> get budgets => _budgets;  static final List<RecurringPayment> _recurringPayments = [    RecurringPayment(      id: 'rp1',      name: 'Netflix',      amount: 15.99,      frequency: 'Monthly',      nextDueDate: DateTime.now().add(const Duration(days: 5)),    ),    RecurringPayment(      id: 'rp2',      name: 'Spotify Premium',      amount: 9.99,      frequency: 'Monthly',      nextDueDate: DateTime.now().add(const Duration(days: 10)),    ),    RecurringPayment(      id: 'rp3',      name: 'Gym Membership',      amount: 45.00,      frequency: 'Monthly',      nextDueDate: DateTime.now().add(const Duration(days: 15)),    ),  ];  static List<RecurringPayment> get recurringPayments => _recurringPayments;  static double getCurrentMonthSpending() {    final now = DateTime.now();    final startOfMonth = DateTime(now.year, now.month, 1);    final endOfMonth = DateTime(now.year, now.month + 1, 0);    return _transactions        .where((t) =>            t.date.isAfter(startOfMonth) &&            t.date.isBefore(endOfMonth) &&            t.amount < 0)        .map((t) => t.amount)        .fold(0.0, (sum, amount) => sum + amount.abs());  }  static double getSpendingByCategory(Category category) {    return _transactions        .where((t) => t.category == category && t.amount < 0)        .map((t) => t.amount)        .fold(0.0, (sum, amount) => sum + amount.abs());  }  static List<Transaction> getTransactionsForCategory(Category category) {    return _transactions        .where((t) => t.category == category && t.amount < 0)        .toList();  }  static List<Transaction> getTransactionsInDateRange(      DateTime startDate, DateTime endDate) {    return _transactions        .where((t) =>            t.date.isAfter(startDate.subtract(const Duration(days: 1))) &&            t.date.isBefore(endDate.add(const Duration(days: 1))))        .toList();  }  static List<Map<String, dynamic>> getSpendingBreakdownByCategories(      DateTime startDate, DateTime endDate) {    final filteredTransactions = getTransactionsInDateRange(startDate, endDate)        .where((t) => t.amount < 0);    final Map<Category, double> categorySpending = {};    for (var t in filteredTransactions) {      categorySpending.update(t.category, (value) => value + t.amount.abs(),          ifAbsent: () => t.amount.abs());    }    final totalSpending = categorySpending.values.fold(0.0, (sum, amount) => sum + amount);    return categorySpending.entries.map((entry) {      return {        'category': entry.key,        'amount': entry.value,        'percentage': totalSpending > 0 ? (entry.value / totalSpending) : 0.0,      };    }).toList();  }  static String formatCurrency(double amount) {    final format = NumberFormat.currency(locale: 'en_US', symbol: 'iks');    return format.format(amount);  }}